def test_pin_change_within_limit_succeeds(api_client, valid_card_id, mocker):
    mocker.patch('requests.post') as mock_post
    mock_post.return_value.status_code = 200
    mock_post.return_value.json.return_value = {
        'card_id': valid_card_id,
        'updated_at': '2024-01-15T10:30:00Z'
    }

    resp = api_client.post(
        f'/cards/{valid_card_id}/pin',
        json={'new_pin': '1234', 'current_pin': '0000'}
    )

    assert resp.status_code == 200
    assert 'updated_at' in resp.json()
    mock_post.assert_called_once()

def test_pin_change_exceeds_rate_limit_rejected(api_client, valid_card_id, mocker):
    mocker.patch('requests.post') as mock_post
    mock_post.return_value.status_code = 429
    mock_post.return_value.json.return_value = {
        'error_code': 'RATE_LIMIT_EXCEEDED',
        'message': 'Maximum 5 PIN changes per 24 hours exceeded'
    }

    resp = api_client.post(
        f'/cards/{valid_card_id}/pin',
        json={'new_pin': '5678', 'current_pin': '1234'}
    )

    assert resp.status_code == 429
    assert resp.json()['error_code'] == 'RATE_LIMIT_EXCEEDED'

