def test_pin_change_resets_after_24hour_window(api_client, valid_card_id, mocker):
    mock_time = mocker.patch('time.time')
    mock_post = mocker.patch('requests.post')

    mock_time.return_value = 86400 + 1
    mock_post.return_value.status_code = 200
    mock_post.return_value.json.return_value = {
        'card_id': valid_card_id,
        'updated_at': '2024-01-16T10:46:00Z',
        'changes_in_window': 1
    }

    resp = api_client.post(
        f'/cards/{valid_card_id}/pin',
        json={'new_pin': '2222', 'current_pin': '9999'}
    )

    assert resp.status_code == 200
    assert resp.json()['changes_in_window'] == 1

def test_pin_change_invalid_card_ownership(api_client, other_customer_card_id, mocker):
    mock_post = mocker.patch('requests.post')
    mock_post.return_value.status_code = 403
    mock_post.return_value.json.return_value = {
        'error_code': 'UNAUTHORIZED_CARD',
        'message': 'Card does not belong to caller'
    }

    resp = api_client.post(
        f'/cards/{other_customer_card_id}/pin',
        json={'new_pin': '1111', 'current_pin': '0000'}
    )

    assert resp.status_code == 403
    assert resp.json()['error_code'] == 'UNAUTHORIZED_CARD'
